import React, { useEffect, useState } from 'react';
import api from '../api';

const DoctorList = () => {
  const [doctors, setDoctors] = useState<any[]>([]);

  useEffect(() => {
    api.get('doctors/')
      .then((res: any) => setDoctors(res.data))
      .catch((err: any) => console.error("Error fetching doctors:", err));
  }, []);

  return (
    <div className="overflow-x-auto bg-white rounded-xl shadow-md border border-gray-100">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-blue-50">
          <tr>
            <th className="px-6 py-4 text-left text-xs font-bold text-blue-600 uppercase">Doctor Name</th>
            <th className="px-6 py-4 text-left text-xs font-bold text-blue-600 uppercase">Specialization</th>
            <th className="px-6 py-4 text-center text-xs font-bold text-blue-600 uppercase">Actions</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {doctors.map((d: any) => (
            <tr key={d.doctor_id} className="hover:bg-blue-50/50 transition-colors">
              <td className="px-6 py-4 text-sm font-medium text-gray-800">{d.full_name}</td>
              <td className="px-6 py-4 text-sm text-gray-600">{d.specialization}</td>
              <td className="px-6 py-4 text-center space-x-2">
                <button className="bg-blue-100 text-blue-700 px-3 py-1 rounded-md text-sm hover:bg-blue-200">View</button>
                <button className="text-red-500 hover:text-red-700 text-sm font-semibold">Remove</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DoctorList;
